code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            long[] dp = new long[N + 1];
            dp[0] = 1;
            if(N >= 1) dp[1] = 1;
            for (int i = 2; i <= N; i++) {
                dp[i] = (dp[i - 1] + dp[i - 2]) % 1000000007;
            }
            System.out.println(dp[N]);
        }
    }
}

